202	reg [15:0] num_ofdm_symbol;
203	
204	integer i;
205	integer j;
206	always @(posedge clock) begin
207	    if (reset) begin
208	        for (j = 0; j < 16; j= j+1) begin
209	            cross_corr_buf[j] <= 0;
210	        end
211	        do_clear();
212	        state <= S_SKIPPING;
213	    end else if (enable) begin
214	        if (sample_in_strobe && state != S_SKIPPING) begin
215	            in_waddr <= in_waddr + 1;
216	            num_input_produced <= num_input_produced + 1;
217	        end
218	        num_input_avail <= num_input_produced - num_input_consumed;
219	
220	        case(state)
221	            S_SKIPPING: begin
222	                // skip the tail of  short preamble
223	                if (num_sample >= NUM_STS_TAIL) begin
224	                    num_sample <= 0;
225	                    state <= S_WAIT_FOR_FIRST_PEAK;
226	                end else if (sample_in_strobe) begin
227	                    num_sample <= num_sample + 1;
228	                end
229	            end
230	
231	            S_WAIT_FOR_FIRST_PEAK: begin
232	                do_mult();
233	
234	                if (metric_stb && (metric > metric_max1)) begin
235	                    metric_max1 <= metric;
236	                    addr1 <= in_raddr - 1;
237	                end
238	
239	                if (num_sample >= 64) begin
240	                    num_sample <= 0;
241	                    addr2 <= 0;
242	                    state <= S_WAIT_FOR_SECOND_PEAK;
243	                end else if (metric_stb) begin
244	                    num_sample <= num_sample + 1;
245	                end
246	
247	            end
248	
249	            S_WAIT_FOR_SECOND_PEAK: begin
250	                do_mult();
251	
252	                if (metric_stb && (metric > metric_max2)) begin
253	                    metric_max2 <= metric;
254	                    addr2 <= in_raddr - 1;
255	                end
256	                gap <= addr2 - addr1;
257	
258	                if (num_sample >= 64) begin
259	                    `ifdef DEBUG_PRINT
260	                        $display("PEAK GAP: %d (%d - %d)", gap, addr2, addr1);
261	                        $display("PHASE OFFSET: %d", phase_offset);
262	                    `endif
263	                    if (gap > 62 && gap < 66) begin
264	                        long_preamble_detected <= 1;
265	                        num_sample <= 0;
266	                        mult_strobe <= 0;
267	                        sum_stb <= 0;
268	                        // offset it by the length of cross correlation buffer
269	                        // size
270	                        in_raddr <= addr1 - 16;
271	                        num_input_consumed <= addr1 - 16;
272	                        in_offset <= 0;
273	                        num_ofdm_symbol <= 0;
274	                        phase_correction <= 0;
275	                        next_phase_correction <= phase_offset;
276	                        state <= S_FFT;
277	                    end else begin
278	                        state <= S_IDLE;
279	                    end
280	                end else if (metric_stb) begin
281	                    num_sample <= num_sample + 1;
282	                end
283	            end
284	
285	            S_FFT: begin
286	                if (long_preamble_detected) begin
287	                    `ifdef DEBUG_PRINT
288	                        $display("Long preamble detected");
289	                    `endif
290	                    long_preamble_detected <= 0;
291	                end
292	
293	                if (~fft_loading && num_input_avail > 64) begin
294	                    fft_start <= 1;
295	                    in_offset <= 0;
296	                end
297	
298	                if (fft_start) begin
299	                    fft_start <= 0;
300	                    fft_loading <= 1;
301	                end
302	
303	                raw_stb <= fft_start | fft_loading;
304	                if (raw_stb) begin
305	                    if (phase_offset > 0) begin
306	                        if (next_phase_correction > PI) begin
307	                            phase_correction <= next_phase_correction - DOUBLE_PI;
308	                            next_phase_correction <= next_phase_correction + phase_offset - DOUBLE_PI;
309	                        end else begin
310	                            phase_correction <= next_phase_correction;
311	                            next_phase_correction <= next_phase_correction + phase_offset;
312	                        end
313	                    end else begin
314	                        if (next_phase_correction < -PI) begin
315	                            phase_correction <= next_phase_correction + DOUBLE_PI;
316	                            phase_correction <= next_phase_correction + DOUBLE_PI + phase_offset;
317	                        end else begin
318	                            phase_correction <= next_phase_correction;
319	                            phase_correction <= next_phase_correction + phase_offset;
320	                        end
321	                    end
322	                end
323	
324	                if (fft_start | fft_loading) begin
325	                    in_offset <= in_offset + 1;
326	
327	                    if (in_offset == 63) begin
328	                        fft_loading <= 0;
329	                        num_ofdm_symbol <= num_ofdm_symbol + 1;
330	                        if (num_ofdm_symbol > 0) begin
331	                            // skip the Guard Interval for data symbols
332	                            in_raddr <= in_raddr + gi_skip;
333	                            num_input_consumed <= num_input_consumed + gi_skip;
334	                        end else begin
335	                            in_raddr <= in_raddr + 1;
336	                            num_input_consumed <= num_input_consumed + 1;
337	                        end
338	                    end else begin
339	                        in_raddr <= in_raddr + 1;
340	                        num_input_consumed <= num_input_consumed + 1;
341	                    end
342	                end
343	
344	                sample_out_strobe <= fft_valid;
345	                sample_out <= fft_out;
346	            end
347	
348	            S_IDLE: begin
349	            end
350	
351	            default: begin
352	                state <= S_WAIT_FOR_FIRST_PEAK;
353	            end
354	        endcase
355	    end else begin
356	        sample_out_strobe <= 0;
357	    end
358	end
359	
360	integer do_mult_i;
361	task do_mult; begin
362	    // cross correlation of the first 16 samples of LTS
363	    if (sample_in_strobe) begin
364	        cross_corr_buf[15] <= sample_in;
365	        for (do_mult_i = 0; do_mult_i < 15; do_mult_i = do_mult_i+1) begin
366	            cross_corr_buf[do_mult_i] <= cross_corr_buf[do_mult_i+1];
367	        end
368	
369	        sum_stage <= 0;
370	        sum_i <= 0;
371	        sum_q <= 0;
372	        sum_stb <= 0;
373	
374	        stage_X0 <= cross_corr_buf[1];
375	        stage_X1 <= cross_corr_buf[2];
376	        stage_X2 <= cross_corr_buf[3];
377	        stage_X3 <= cross_corr_buf[4];
378	
379	        stage_Y0[31:16] <= 156;
380	        stage_Y0[15:0] <= 0;
381	        stage_Y1[31:16] <= -5;
382	        stage_Y1[15:0] <= 120;
383	        stage_Y2[31:16] <= 40;
384	        stage_Y2[15:0] <= 111;
385	        stage_Y3[31:16] <= 97;
386	        stage_Y3[15:0] <= -83;
387	
388	        mult_strobe <= 1;
389	        mult_stage <= 1;
390	    end
391	
392	    if (mult_stage == 1) begin
393	        stage_X0 <= cross_corr_buf[4];
394	        stage_X1 <= cross_corr_buf[5];
395	        stage_X2 <= cross_corr_buf[6];
396	        stage_X3 <= cross_corr_buf[7];
397	
398	        stage_Y0[31:16] <= 21;
399	        stage_Y0[15:0] <= -28;
400	        stage_Y1[31:16] <= 60;
401	        stage_Y1[15:0] <= 88;
402	        stage_Y2[31:16] <= -115;
403	        stage_Y2[15:0] <= 55;
404	        stage_Y3[31:16] <= -38;
405	        stage_Y3[15:0] <= 106;
406	
407	        mult_stage <= 2;
408	    end else if (mult_stage == 2) begin
409	        stage_X0 <= cross_corr_buf[8];
410	        stage_X1 <= cross_corr_buf[9];
411	        stage_X2 <= cross_corr_buf[10];
412	        stage_X3 <= cross_corr_buf[11];
413	
414	        stage_Y0[31:16] <= 98;
415	        stage_Y0[15:0] <= 26;
416	        stage_Y1[31:16] <= 53;
417	        stage_Y1[15:0] <= -4;
418	        stage_Y2[31:16] <= 1;
419	        stage_Y2[15:0] <= 115;
420	        stage_Y3[31:16] <= -137;
421	        stage_Y3[15:0] <= 47;
422	
423	        mult_stage <= 3;
424	    end else if (mult_stage == 3) begin
425	        stage_X0 <= cross_corr_buf[12];
426	        stage_X1 <= cross_corr_buf[13];
427	        stage_X2 <= cross_corr_buf[14];
428	        stage_X3 <= cross_corr_buf[15];
429	
430	        stage_Y0[31:16] <= 24;
431	        stage_Y0[15:0] <= 59;
432	        stage_Y1[31:16] <= 59;
433	        stage_Y1[15:0] <= 15;
434	        stage_Y2[31:16] <= -22;
